insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'chiyoda'), 'tokyo-chiyoda-welfare-taxi', '福祉タクシー券の支給（千代田区）', '千代田区では、重度の障害のある方等の外出・通院を支えるため、区と契約しているタクシーを利用できる福祉タクシー券を交付しています。あわせて、自動車を利用する方を対象とした自動車燃料費助成も設けられており、いずれか一方を選択して利用する制度です（公式で確認。詳細・最新の取扱いは区にご確認ください）。', '障害のある方がタクシーで出かけるときに使える「福祉タクシー券」を、千代田区がお渡しする制度です。車を使う方には、かわりにガソリン代を助成する制度もあり、どちらか一方を選んで利用します。', 'service', '公式によると、千代田区内に在住で、身体障害者手帳の下肢・体幹・内部障害1～3級、上肢・視覚障害1・2級、東京都愛の手帳（療育手帳）1・2度、難病患者で障害者福祉手当を受給している方、脳性麻痺・進行性筋萎縮症の方などが対象となる可能性があります。なお、施設に入所している方、および自動車燃料費助成・自動車駐車場助成を受けている方は対象外とされています。ご自身が対象となるかは公式・窓口でご確認ください。', '公式ページによると、福祉タクシー券は4か月につき1冊（15,000円分）を交付し、申請月によって交付冊数が異なり、年間3冊（45,000円分）が限度とされています。自動車燃料費助成を選ぶ場合は、月額上限3,750円（実際の燃料費がこれを下回る場合はその額）とされています。金額・冊数・限度額は変更される可能性があるため、最新の内容は区にご確認ください。', '公式ページに申請期限の明確な記載は確認できませんでした。福祉タクシー券は申請月によって交付冊数が異なるため、利用を希望する場合は早めに区の窓口へお問い合わせください。', '千代田区 保健福祉部障害者福祉課給付・指導担当の窓口へ申請します（電話：03-5211-4128）。自動車燃料費助成を選ぶ場合は、身体障害者手帳・愛の手帳・難病の医療券などのいずれか、運転免許証、車検証などが必要とされています。具体的な必要書類・手続きは区の窓口にご確認ください。', '自動車燃料費助成を選ぶ場合、公式によると身体障害者手帳・愛の手帳・難病の医療券などのいずれか、運転免許証、車検証が必要とされています。福祉タクシー券の必要書類は公式ページに明記がないため、区の窓口でご確認ください。', FALSE, '千代田区 保健福祉部障害者福祉課 給付・指導担当', '03-5211-4128', 'https://www.city.chiyoda.lg.jp/koho/kenko/shogaisha/techo/josei/fukushitaxi.html', 'https://www.city.chiyoda.lg.jp/koho/kenko/shogaisha/techo/josei/fukushitaxi.html', '福祉タクシー券の支給 - 千代田区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は千代田区公式サイト（確認日2026-06-24、福祉タクシー券ページの最終更新2023-04-13）に基づく概要です。対象要件・交付額・年間限度額・燃料費助成額・必要書類などは変更される場合があります。受給を確約するものではなく、対象可否や最新の取扱いは必ず千代田区の公式ページまたは障害者福祉課にご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
