insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot welfare-taxi import', '{"slug":"tokyo-chiyoda-welfare-taxi","status":"published","title":"福祉タクシー券の支給（千代田区）","officialUrl":"https://www.city.chiyoda.lg.jp/koho/kenko/shogaisha/techo/josei/fukushitaxi.html","topic":"welfare-taxi"}'::jsonb, 'pilot:tokyo-chiyoda-welfare-taxi:dG9reW8tY2hpeW9kYS13ZWxmYXJlLXRheGl856aP' from public.support_programs sp where sp.slug='tokyo-chiyoda-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'chuo'), 'tokyo-chuo-welfare-taxi', '福祉タクシー利用券の給付（自動車燃料費の助成）', '中央区の障害のある方の外出・通院を支える制度。福祉タクシー利用券の給付、または自家用車を所有する方への自動車燃料費（ガソリン費）助成のいずれかを年1回交付する制度として、区公式サイトで案内されています。令和7年度より年間給付（助成）額が48,000円に増額されました（申請月により給付額が異なります）。対象等級・金額・回数などの詳細は中央区の公式ページでご確認ください。', '障害のある方の外出や通院を支えるため、中央区では「福祉タクシーの利用券」または「自分の車のガソリン代の助成」のどちらかを、1年に1回受け取れる制度を案内しています。対象になる方や金額は障害の種類・等級などで決まります。施設に入っている方は対象外です。詳しくは区の公式ページや障害者福祉課（電話03-3546-5389）で確認してください。', 'service', '重度の身体・知的・精神障害のある区民の方が対象となる可能性があります。公式では、身体障害者手帳（下肢・体幹障害1〜3級、内部・視覚障害1・2級）、愛の手帳1・2度、精神障害者保健福祉手帳1級などの方が該当すると案内されています。福祉施設に入所している方は申請できません。対象となる障害種別・等級の詳細は中央区の公式ページで確認してください。', '年間給付（助成）額は令和7年度より48,000円。申請月により給付額が異なります（公式では4〜6月48,000円／7〜9月36,000円／10〜12月24,000円／1〜3月12,000円と案内）。金額・改定は変更される可能性があるため公式で確認してください。', '年1回の交付。申請月により給付額が異なります。詳細な申請時期は中央区の公式ページで確認してください。', '区役所本庁舎4階の障害者福祉課窓口で申請します。福祉タクシー利用券は4〜6月に限り日本橋・月島・晴海の各特別出張所でも申請できます。既に交付を受けている方には毎年2月下旬に案内と申請書が郵送されます（公式で確認）。福祉タクシー利用券と自動車燃料費助成はいずれか一方の選択となります。', '障害者手帳（共通）。自動車燃料費助成の場合は加えて自動車検査証（車検証）、運転免許証、障害者本人名義の口座のわかるもの（通帳など）が必要と案内されています。代理申請時は委任状・本人確認書類が必要となる場合があります。最新の必要書類は公式で確認してください。', FALSE, '中央区 福祉保健部 障害者福祉課 障害者福祉係', '03-3546-5389', NULL, 'https://www.city.chuo.lg.jp/a0023/kenkouiryou/shougaishafukushi/shienservice/seikatuken/takusir.html', '福祉タクシー利用券の給付（自動車燃料費の助成） - 中央区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText']::text[], '本情報は中央区公式サイトの確認日（2026-06-24）時点の内容に基づく概要です。対象要件・給付額・申請方法は変更される場合があります。実際の対象可否や手続きは必ず中央区の公式ページおよび障害者福祉課の窓口でご確認ください。当サイトは申請の代行や受給の保証は行いません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
