insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot welfare-taxi import', '{"slug":"tokyo-chuo-welfare-taxi","status":"published","title":"福祉タクシー利用券の給付（自動車燃料費の助成）","officialUrl":"https://www.city.chuo.lg.jp/a0023/kenkouiryou/shougaishafukushi/shienservice/seikatuken/takusir.html","topic":"welfare-taxi"}'::jsonb, 'pilot:tokyo-chuo-welfare-taxi:dG9reW8tY2h1by13ZWxmYXJlLXRheGl856aP56WJ' from public.support_programs sp where sp.slug='tokyo-chuo-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'minato'), 'tokyo-minato-welfare-taxi', '福祉タクシー利用券の給付・自動車燃料費助成（港区）', '港区が、重度の障害などにより外出・通院に支援が必要な方を対象に、タクシー利用券の給付または自動車燃料費の助成を行う移動支援制度です。タクシー利用券と燃料費助成は、いずれか一方を選んで利用する形で、併給はできません。対象や限度額は港区の公式ページで確認してください。', '障害のある方が外出や通院をしやすいように、港区がタクシー券、または自動車のガソリン代の助成のどちらかを選んで使える制度です。両方を同時には使えません。', 'service', '公式によると、身体障害者手帳（下肢・体幹機能障害または視覚障害1～3級、内部障害1級、呼吸器機能障害1・3級）、愛の手帳1・2度、精神障害者保健福祉手帳1級をお持ちの方、および特定の医療的ケアを受けている18歳未満の児童などが対象となる可能性があります。詳しい対象者・等級は港区の公式ページでご確認ください。', '公式によると、年間52,000円分を上限に給付・助成されます（新規申請の時期によって限度額が逓減し、7～9月は39,000円、10～12月は26,000円、1～3月は13,000円となる可能性があります）。最新の金額は公式ページでご確認ください。', '申請時期により限度額が異なる場合があります。自動車燃料費助成は年1回、領収書を添付して請求する方式とされています。詳細は公式でご確認ください。', '各総合支所 区民課 保健福祉係の窓口で申請します。電子申請も利用できる場合があります。申請書、障害者手帳（手帳所持者）、医療的ケア児は医師確認書、自動車燃料費助成では車検証などが必要となる可能性があります。詳細・最新の手続きは港区の公式ページでご確認ください。', '申請書、障害者手帳（手帳所持者のみ）、医師確認書（医療的ケア児のみ）。自動車燃料費助成では車検証も必要となる可能性があります。', TRUE, '港区 各総合支所 区民課 保健福祉係', '03-3578-2111', NULL, 'https://www.city.minato.tokyo.jp/kenko/fukushi/shogaisha/shakaisanka/taxi.html', '港区ホームページ／タクシー利用券の給付', '2026-06-24', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '対象となる障害の種別・等級、交付額・利用回数などの詳細は変更される場合があります。実際の対象可否や金額は港区の公式ページおよび窓口で必ずご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
