insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot welfare-taxi import', '{"slug":"tokyo-minato-welfare-taxi","status":"published","title":"福祉タクシー利用券の給付・自動車燃料費助成（港区）","officialUrl":"https://www.city.minato.tokyo.jp/kenko/fukushi/shogaisha/shakaisanka/taxi.html","topic":"welfare-taxi"}'::jsonb, 'pilot:tokyo-minato-welfare-taxi:dG9reW8tbWluYXRvLXdlbGZhcmUtdGF4aXznpo/n' from public.support_programs sp where sp.slug='tokyo-minato-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shinjuku'), 'tokyo-shinjuku-welfare-taxi', '心身障害者福祉タクシー券・自動車燃料費助成（新宿区）', '新宿区が、重度の身体障害・知的障害のある方等の外出や通院を支えるために設けている移動支援制度です。区が契約したタクシー会社で使える福祉タクシー利用券（月額4,000円分）を交付する制度と、自家用車を持つ方向けに自動車燃料費（ガソリン代）を助成する制度があり、いずれかを選んで利用できます（両方を同時に受けることはできません）。対象等級や交付額・助成額の詳細は新宿区の公式ページで確認できます。', '障害のある方の外出や通院を助けるための新宿区の制度です。タクシーで使える利用券（月4,000円分）をもらう方法と、自分の車のガソリン代を助成してもらう方法があり、どちらか一方を選びます。まずは障害者手帳を持って区の障害者福祉課に相談・申請します。', 'service', '新宿区に住み、一定の障害がある方が対象となる可能性があります。公式の案内では、身体障害者手帳で下肢・体幹・移動機能障害・内部障害1〜3級、視覚障害1〜2級、平衡機能障害3級、または愛の手帳1〜2度の方が対象とされています。燃料費助成を選ぶ場合は、加えて自動車税・軽自動車税（4輪のみ）の減免を受けていることが条件とされています。具体的な対象等級・条件は新宿区の公式ページでご確認ください。', '公式の案内では、福祉タクシー利用券は月額4,000円分を交付。自動車燃料費助成は月3,150円を限度に助成（令和5年4月から当面の間は月3,510円に引き上げと案内）。福祉タクシー券と燃料費助成は併給できないとされています。最新の金額・条件は新宿区公式ページでご確認ください。', NULL, '公式の案内では、身体障害者手帳または愛の手帳を持参のうえ、新宿区障害者福祉課（相談係）の窓口で申請します。燃料費助成を選ぶ場合は、自動車税等の減免を受けていることがわかるものや本人名義の預金通帳も必要とされ、登録認定後に燃料購入の領収書を添えて3か月ごとに交付申請するとされています。詳しい手続きは公式ページ・窓口でご確認ください。', '公式の案内では、福祉タクシー券は身体障害者手帳または愛の手帳。燃料費助成は、これに加えて自動車税種別割・軽自動車税種別割の減免を受けていることがわかるもの、本人の預金通帳が必要とされています。詳細は公式ページでご確認ください。', FALSE, '新宿区 障害者福祉課（相談係／経理係）', '03-5273-4518', 'https://www.city.shinjuku.lg.jp/fukushi/index06_04_03.html', 'https://www.city.shinjuku.lg.jp/fukushi/file06_04_00022.html', '心身障害者福祉タクシー券（福祉タクシー利用券） - 新宿区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本ページは新宿区の公式情報をもとにした概要です。対象等級・金額・条件は変更される場合があります。最新かつ正確な内容は必ず新宿区の公式ページまたは窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
