insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot welfare-taxi import', '{"slug":"tokyo-shinjuku-welfare-taxi","status":"published","title":"心身障害者福祉タクシー券・自動車燃料費助成（新宿区）","officialUrl":"https://www.city.shinjuku.lg.jp/fukushi/file06_04_00022.html","topic":"welfare-taxi"}'::jsonb, 'pilot:tokyo-shinjuku-welfare-taxi:dG9reW8tc2hpbmp1a3Utd2VsZmFyZS10YXhpfOW/' from public.support_programs sp where sp.slug='tokyo-shinjuku-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'bunkyo'), 'tokyo-bunkyo-welfare-taxi', '福祉タクシー券の交付（文京区）', '文京区が行う障害のある方の外出・移動を支える区独自制度です。重度の身体・知的・精神障害のある方等を対象に、月額4,100円分の福祉タクシー利用券（500円券・100円券の組み合わせ）を交付します。私的自動車を利用する方向けの自動車燃料費助成（月額4,100円）もありますが、福祉タクシー券との併給はできません。所得制限があり、対象等級や限度額は公式で確認が必要です。', '外出や通院がたいへんな障害のある方のために、文京区がタクシー代の利用券（月4,100円分）を出してくれる制度です。自家用車を使う方は、かわりにガソリン代の助成（月4,100円）を選ぶこともできますが、両方はもらえません。手帳の種類や等級、所得の条件があるので、まず区の障害福祉課に問い合わせてください。', 'service', '文京区内に住む重度の障害のある方等が対象となる可能性があります。公式では、身体障害者手帳（視覚障害1・2級、下肢・体幹機能障害1〜3級、内部障害1・2級、移動機能障害1・2級、平衡機能障害3級ほか）、愛の手帳1・2度、精神障害者保健福祉手帳1級、難病等の医療受給者などが対象とされています。所得制限があり、対象等級・限度額の詳細は公式で確認してください。', '福祉タクシー券は月額4,100円分（500円券・100円券の組み合わせで交付）。自動車燃料費助成を選ぶ場合は月額4,100円（併給不可）。金額・交付方法は公式で確認してください。', '公式ページで確認してください。', '必要書類を持参して、福祉部障害福祉課障害者在宅サービス係（文京シビックセンター9階北側）の窓口で申請します。精神障害者保健福祉手帳をお持ちの方は予防対策課への相談が必要です。詳細・最新の取扱いは公式ページで確認してください。', '手帳（身体障害者手帳・愛の手帳・精神障害者保健福祉手帳）または医療受給者証、マイナンバーカードまたは通知カード（20歳未満の場合は扶養義務者のもの）など。自動車燃料費助成を選ぶ場合は、運転免許証、自動車検査証または軽自動車届出済証、本人名義の預金通帳も必要です。詳細は公式で確認してください。', FALSE, '文京区 福祉部障害福祉課 障害者在宅サービス係', '03-5803-1212', 'https://www.city.bunkyo.lg.jp/b018/p003420.html', 'https://www.city.bunkyo.lg.jp/b018/p003420.html', '福祉タクシー | 文京区', '2026-06-24', 'high', ARRAY['targetPeople', 'benefitAmountText', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '対象となるかどうかや交付額は、手帳の種類・等級や所得などの条件により異なります。最新の正確な情報は文京区の公式ページおよび障害福祉課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
