insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot welfare-taxi import', '{"slug":"tokyo-bunkyo-welfare-taxi","status":"published","title":"福祉タクシー券の交付（文京区）","officialUrl":"https://www.city.bunkyo.lg.jp/b018/p003420.html","topic":"welfare-taxi"}'::jsonb, 'pilot:tokyo-bunkyo-welfare-taxi:dG9reW8tYnVua3lvLXdlbGZhcmUtdGF4aXznpo/n' from public.support_programs sp where sp.slug='tokyo-bunkyo-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'taito'), 'tokyo-taito-welfare-taxi', '福祉タクシー利用券・自動車燃料費の助成（障害者）', '台東区が、外出が困難な障害のある方の通院・外出を支えるため、福祉タクシー利用券の交付、または自家用車の自動車燃料費の助成を行う区独自の移動支援制度です。身体障害者手帳・愛の手帳の交付を受け一定の障害種別・等級に該当する方が対象となる可能性があり、所得制限があります。福祉タクシー券と燃料費助成は併給できません。詳細・最新情報は台東区公式ページでご確認ください。', '外出や通院がむずかしい障害のある方のために、台東区がタクシー代を助ける「福祉タクシー利用券」を出すか、自家用車のガソリン代を助ける制度です。手帳の種類や等級などの条件があり、所得による制限もあります。タクシー券とガソリン代助成は、どちらか一方しか使えません。利用できるかどうかは、台東区の障害福祉課（電話03-5246-1201）に確認してください。', 'service', '台東区内に住所があり、身体障害者手帳または愛の手帳（知的障害）の交付を受けている方のうち、一定の障害種別・等級に該当する方が対象となる可能性があります。公式ページの記載では、福祉タクシー利用券は視覚機能障害1〜2級、上肢機能障害1級、下肢機能障害1〜3級、体幹機能障害1〜3級、脳病変による運動機能障害（上肢1級・移動1〜3級）、内部機能障害（心臓・腎臓・呼吸器・膀胱・直腸・小腸・HIV免疫・肝臓）1〜3級、知的障害の程度1〜2度などが挙げられています。自動車燃料費の助成は自動車税の減免を受けていることなどが要件で、対象等級が異なります。いずれも所得制限があり、本人（20歳未満は扶養義務者）の所得が限度額を超える場合は対象外となります。対象の可否・等級・所得基準は必ず台東区公式でご確認ください。', '福祉タクシー利用券は「1ヶ月あたり4,000円相当額分」を交付（公式記載）。自動車燃料費の助成は「月額2,200円を限度」として助成（公式記載）。福祉タクシー券と燃料費助成は併給できません。金額・交付方法の詳細や最新の取扱いは台東区公式でご確認ください。', '公式ページに申請期限の明確な記載は確認できませんでした。取扱いは台東区公式・障害福祉課へご確認ください。', '申請窓口は台東区 障害福祉課 給付担当（電話03-5246-1201、ファクス03-5246-1179）です。福祉タクシー利用券の申請には身体障害者手帳または愛の手帳が必要で、転入の方は個人番号（本人および扶養義務者等）と本人確認書類も必要とされています。自動車燃料費の助成では、手帳のほか車検証の写し、自動車税減免決定通知書、運転免許証の写し（該当時）、印鑑、預金通帳、課税（非課税）証明書（転入者のみ）などが必要とされています。具体的な申請手順・必要書類は事前に窓口へご確認ください。', '福祉タクシー利用券：身体障害者手帳または愛の手帳（転入の方は個人番号〔本人・扶養義務者等〕と本人確認書類）。自動車燃料費の助成：身体障害者手帳または愛の手帳、車検証の写し、自動車税減免決定通知書、運転免許証の写し（該当時）、印鑑、預金通帳、課税（非課税）証明書（転入者のみ）。詳細は窓口でご確認ください。', FALSE, '台東区 健康部 障害福祉課 給付担当', '03-5246-1201', 'https://www.city.taito.lg.jp/kenkohukusi/shogai/service/seikatuken/shaji/fukusitaxi.html', 'https://www.city.taito.lg.jp/kenkohukusi/shogai/service/seikatuken/shaji/fukusitaxi.html', '福祉タクシー｜台東区ホームページ', '2026-06-24', 'high', ARRAY['対象となる具体的な障害種別・等級の全範囲', '所得制限の限度額（基準額一覧の具体額）', '福祉タクシー利用券の年間交付額・券の使用条件', '自動車燃料費助成の対象範囲・自動車税減免要件の詳細', '申請期限']::text[], '本情報は2026-06-24時点で台東区公式サイトを確認して作成した概要です。対象等級・交付額・所得制限・申請方法などは変更される場合があり、最終的な可否は区の審査によります。必ず台東区公式ページおよび障害福祉課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
