insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot welfare-taxi import', '{"slug":"tokyo-taito-welfare-taxi","status":"published","title":"福祉タクシー利用券・自動車燃料費の助成（障害者）","officialUrl":"https://www.city.taito.lg.jp/kenkohukusi/shogai/service/seikatuken/shaji/fukusitaxi.html","topic":"welfare-taxi"}'::jsonb, 'pilot:tokyo-taito-welfare-taxi:dG9reW8tdGFpdG8td2VsZmFyZS10YXhpfOemj+el' from public.support_programs sp where sp.slug='tokyo-taito-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'sumida'), 'tokyo-sumida-welfare-taxi', '心身障害者福祉タクシー料金・自動車燃料費助成共通券の交付（墨田区）', '墨田区が、心身に障害があり他の交通機関の利用が困難な方を対象に、タクシー料金と自動車燃料費（ガソリン代）の両方に使える「福祉タクシー料金・自動車燃料費助成共通券」を交付する制度です。区が契約するタクシー事業者やガソリンスタンドで、交付を受けた本人が乗車している場合に利用できます。対象や交付額は障害の種別・等級や申請月によって異なるため、詳細は公式ページと窓口で確認が必要です。', '墨田区では、障害があってバスや電車などを使うのが難しい方に、タクシー代とガソリン代の両方に使える共通の助成券を交付しています。区と契約したタクシー会社やガソリンスタンドで、本人が乗っているときに使えます。対象や金額は障害の種類・等級や申請する月によって変わるので、墨田区の障害者福祉課（電話03-5608-6163）に確認してください。', 'service', '墨田区に住み、心身の障害により他の交通機関の利用が困難な方が対象となる可能性があります。公式ページでは、視覚障害1～2級、下肢・体幹機能障害または脳病変移動機能障害1～3級、内部障害1～2級、愛の手帳（知的障害）1～2度などが対象として挙げられています。対象となる障害種別・等級の詳細は墨田区の公式情報および窓口でご確認ください。', '公式ページによると、交付額は申請月により異なり、4～6月の申請で30,000円分、以後申請月が1か月遅れるごとに5,000円ずつ減額されるとされています（目安として4～6月は30,000円、7～9月は25,000円、10～12月は20,000円、1～3月は15,000円程度）。さらに、個別等級が下肢・体幹機能障害1級・脳病変移動機能障害1級・腎臓機能障害1級など指定された方には10,000円が加算されるとされています。実際の交付額は年度・申請月・個別の判定により変わる場合があるため、公式でご確認ください。', NULL, '対象となる方で交付を希望する場合は、必要なものを持参のうえ、墨田区役所3階の障害者福祉課障害者給付係で申請するとされています。申請に必要なものは身体障害者手帳または愛の手帳で、ガソリン給油での利用を希望する場合は車両番号が分かるもの、代理人が申請する場合は代理人の身分証明書も必要とされています。詳細・最新の手続きは公式ページおよび窓口でご確認ください。', '身体障害者手帳または愛の手帳。ガソリン給油での利用を希望する場合は、登録する車両の番号が分かるもの。代理人申請の場合は代理人の身分証明書（公式ページに基づく）。', FALSE, '墨田区 障害者福祉課 障害者給付係', '03-5608-6163', NULL, 'https://www.city.sumida.lg.jp/kenko_fukushi/syougai/waribiki/taxi.html', '心身障害者福祉タクシー料金・自動車燃料費助成共通券の交付（墨田区公式ホームページ）', '2026-06-24', 'high', ARRAY['対象となる障害種別・等級の詳細', '交付額（申請月・個別等級による加算分を含む）', '利用回数・有効期限', '契約タクシー事業者およびガソリンスタンドの範囲']::text[], '本情報は墨田区公式サイト（2026年4月1日更新）に基づく概要です。対象となる障害種別・等級、交付額、利用方法の細目は変更される場合があり、個別の判定によっても異なります。最新かつ正確な内容は必ず墨田区の公式ページおよび障害者福祉課の窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
