insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot welfare-taxi import', '{"slug":"tokyo-sumida-welfare-taxi","status":"published","title":"心身障害者福祉タクシー料金・自動車燃料費助成共通券の交付（墨田区）","officialUrl":"https://www.city.sumida.lg.jp/kenko_fukushi/syougai/waribiki/taxi.html","topic":"welfare-taxi"}'::jsonb, 'pilot:tokyo-sumida-welfare-taxi:dG9reW8tc3VtaWRhLXdlbGZhcmUtdGF4aXzlv4Po' from public.support_programs sp where sp.slug='tokyo-sumida-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'koto'), 'tokyo-koto-welfare-taxi', '福祉タクシー券・自動車燃料費助成（江東区）', '江東区が、一般の交通機関の利用が困難な重度の障害がある方等を対象に、外出・通院を支えるため、福祉タクシー券（年額43,800円を限度に500円券・100円券で交付）または自動車燃料費助成（ガソリン購入月ごとに月額3,650円を限度に助成）を行う区独自制度です。福祉タクシー券と燃料費助成は同じ対象層向けで、どちらか一方のみ利用でき、両方を同時に受けることはできません（併給不可）。介護保険の介護タクシー（通院等乗降介助）とは別の制度です。', 'タクシー代の一部に使える福祉タクシー券（年間で最大43,800円分）か、自分の車のガソリン代の助成（月最大3,650円）の、どちらか一方を受けられる可能性がある制度です（両方は受けられません）。重い障害があり、一般の電車・バスでの外出が難しい方が対象になる可能性があります。利用には申請が必要で、対象や金額は公式サイト・窓口でご確認ください。', 'service', '区内在宅で、身体障害者手帳1級（視覚障害は1・2級、下肢・体幹・移動機能障害は1～3級）または愛の手帳1・2度に該当する方などが対象となる可能性があります。詳しい対象範囲は公式で確認してください。福祉タクシー券と自動車燃料費助成は、どちらか一方のみ利用でき、両方を同時に受けることはできません（併給不可）。', '福祉タクシー券：500円券と100円券の組み合わせで年額43,800円を限度に交付。自動車燃料費助成：ガソリンを購入した月ごとに月額3,650円を限度。詳細は公式で確認してください。', '自動車燃料費助成の請求は1月・4月・7月・10月の年4回、前3か月分をまとめて行うとされています（公式で確認）。', '窓口または郵送で申請を受け付け。福祉タクシー券は申請年度分を交付し、翌年度以降は年間分を郵送（公式で確認）。自動車燃料費助成は申請後にガソリン領収書を提出して請求します（公式で確認）。', '福祉タクシー券：江東区心身障害者福祉タクシー申請書（該当時は心身障害者援護事業受給者異動届）。自動車燃料費助成：身体障害者手帳または愛の手帳、運転免許証、自動車検査証、本人名義の預貯金通帳、認定申請書など。詳細は公式・窓口で確認してください。', FALSE, '江東区 障害福祉部 障害者支援課 障害者福祉係（防災センター2階11番）', '03-3647-4952', 'https://www.city.koto.lg.jp/222015/fukushi/shogaisha/waribiki/jose/6708.html', 'https://www.city.koto.lg.jp/222015/fukushi/shogaisha/waribiki/jose/6708.html', '福祉タクシー券 - 江東区', '2026-06-24', 'high', ARRAY['対象となる障害等級の範囲', '福祉タクシー券の交付額・利用回数', '自動車燃料費助成の助成額の上限・要件', '申請期限・請求時期の細部']::text[], '本情報は江東区公式サイト（2026-06-24確認）に基づく概要です。対象となる障害等級・交付額・利用回数・申請手続きの細部は変更される場合があります。福祉タクシー券と自動車燃料費助成は併給できず、いずれか一方の利用となります。必ず公式サイトまたは障害者支援課にご確認ください。受給を確約するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
