insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shinagawa'), 'tokyo-shinagawa-welfare-taxi', '福祉タクシー・自動車燃料費助成券の交付（品川区）', '品川区が、外出が困難な障害のある方に対し、日常生活に必要なタクシー利用料金または自動車燃料費の一部を助成する制度です。1つの助成券でタクシーと燃料費の両方に対応でき、1カ月あたり3,500円分が交付される可能性があります。対象や金額の詳細は公式で確認してください。', '品川区にお住まいで、一定の障害がある方が、タクシー代やガソリン代の一部を助成してもらえる券を受け取れる可能性がある制度です。まず障害者支援課で手帳を見せて引換券をもらい、それを区の社会福祉協議会に持っていくと助成券を受け取れます。対象や金額は公式ページで確認してください。', 'service', '品川区に住所があり、下肢・体幹機能障害1～3級、視覚障害1・2級、内部障害1級、または愛の手帳1・2度のいずれかに該当する方が対象となる可能性があります。詳しい障害種別・等級の要件は公式ページで確認してください。', '1カ月あたり3,500円分の助成券が交付される可能性があります（公式情報。500円券＝福祉タクシーまたは自動車燃料費に選択利用可、100円券＝福祉タクシー専用。券種の組み合わせはタクシー専用券の要否で異なります）。金額・券種は変更される場合があるため公式で確認してください。', '公式ページに申請期限の明記は確認できませんでした。詳細は窓口へお問い合わせください。', '障害者支援課の窓口に身体障害者手帳または愛の手帳を持参して引換券を受け取り、その引換券を品川区社会福祉協議会の窓口に提出して助成券を受け取る流れと公式で案内されています。手続きの詳細は公式ページで確認してください。', '身体障害者手帳または愛の手帳（公式案内）。その他必要書類は公式・窓口で確認してください。', FALSE, '品川区 障害者支援課 障害者支援係（申請）／品川区社会福祉協議会（交付）', '03-5742-6707', 'https://www.city.shinagawa.tokyo.jp/PC/kenkou/kenkou-syogai/kenkou-syogai-seikatsuken/hpg000033560.html', 'https://www.city.shinagawa.tokyo.jp/PC/kenkou/kenkou-syogai/kenkou-syogai-seikatsuken/hpg000033560.html', '福祉タクシー・自動車燃料費助成券の交付｜品川区', '2026-06-24', 'high', ARRAY['applicationDeadlineText', 'onlineApplicationAvailable', 'benefitAmountText', 'targetPeople']::text[], '本情報は2026年6月時点で品川区公式サイトを基に作成しています。対象要件・助成額・利用方法は変更される場合があります。申請にあたっては必ず品川区公式ページおよび窓口で最新情報をご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
