insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot welfare-taxi import', '{"slug":"tokyo-shinagawa-welfare-taxi","status":"published","title":"福祉タクシー・自動車燃料費助成券の交付（品川区）","officialUrl":"https://www.city.shinagawa.tokyo.jp/PC/kenkou/kenkou-syogai/kenkou-syogai-seikatsuken/hpg000033560.html","topic":"welfare-taxi"}'::jsonb, 'pilot:tokyo-shinagawa-welfare-taxi:dG9reW8tc2hpbmFnYXdhLXdlbGZhcmUtdGF4aXzn' from public.support_programs sp where sp.slug='tokyo-shinagawa-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'meguro'), 'tokyo-meguro-welfare-taxi', '福祉タクシー利用券の給付・自動車燃料費の助成（目黒区）', '目黒区が、重度の身体・知的障害のある方や区指定の難病の方等を対象に、外出・通院を支えるため、区契約タクシーに乗車できる福祉タクシー利用券（4か月1万円分）の交付、または自動車のガソリン代・軽油代の助成（月額2,500円を限度に4か月毎）を行う区独自の移動支援制度。福祉タクシー券と燃料費助成は併給できず、いずれか一方を選択する。所得制限あり。詳細・対象は目黒区公式で確認のこと。', '目黒区にお住まいで重い障害のある方などが、外出や通院をしやすくするための制度です。区が契約したタクシーに使える「福祉タクシー利用券」をもらう方法と、自家用車のガソリン代・軽油代を助成してもらう方法のどちらかを選べます。タクシー券は4か月で1万円分、燃料費助成は月2,500円を上限に4か月ごとに支給されます（両方を同時に受けることはできません）。所得による制限があります。対象になるかどうかや金額などは年度で変わることがあるので、目黒区の公式ページや障害者支援課でご確認ください。', 'service', '目黒区に住む心身障害のある方が対象となる可能性がある。公式では、下肢・体幹・内部障害で総合等級1～3級、上肢・視覚障害で総合等級1～2級、愛の手帳1度・2度、脳性マヒまたは進行性筋萎縮症、区で指定する特殊疾病（難病）で東京都発行の特定医療費（指定難病）受給者証の交付を受けている方等が挙げられている。所得制限があり、施設入所中・入院中の方は燃料費助成の対象外とされる。対象等級・要件の詳細は目黒区公式で確認が必要。', '福祉タクシー利用券は、区が契約したタクシー会社のタクシーに乗車できる利用券を4か月1万円分として、請求の時期から翌年3月分まで交付（公式で確認）。自動車燃料費の助成は、ガソリン代・軽油代を月額2,500円を限度として4か月毎に給付（公式で確認）。福祉タクシー券と燃料費助成は併給できず、いずれか一方の選択となる。交付額・回数は年度により変わる可能性があるため最新情報は公式で確認のこと。', '随時受付とみられるが、給付対象期間との関係があるため、申請時期は目黒区障害者支援課へ確認するとよい。', '申請書（福祉タクシー利用券は交付申請書、燃料費助成は心身障害者自動車燃料費認定登録申請書）に必要事項を記入し、身体障害者手帳・愛の手帳等の写し、住民税課税証明書（燃料費助成は車検証の写しも）を添付して、目黒区障害者支援課 支援サービス係へ提出する（公式で確認）。詳しい持ち物・手続きは事前に窓口へ確認するとよい。', '身体障害者手帳・愛の手帳もしくは特定医療費（指定難病）受給者証の写し、各控除が明記された住民税課税（非課税）証明書など。自動車燃料費助成では本人または同居家族名義の車の車検証の写しも必要とされる（公式で確認。詳細は窓口に確認のこと）。', FALSE, '目黒区 障害者支援課 支援サービス係', '03-5722-9846', 'https://www.city.meguro.tokyo.jp/kurashi/shogai_fukushi/enjo/traffic/index.html', 'https://www.city.meguro.tokyo.jp/shougaishien/kenkoufukushi/shougaisha/fukusitakusii.html', '福祉タクシー利用券の給付 | 目黒区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'requiredDocumentsText', 'applicationDeadlineText']::text[], '対象要件・所得基準・交付額・申請方法は変更される場合があります。最新かつ正確な情報は必ず目黒区の公式ページおよび障害者支援課でご確認ください。本情報は申請による受給を確約するものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
