insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'ota'), 'tokyo-ota-welfare-taxi', '移送サービス利用券（福祉タクシー・自動車燃料費助成）', '大田区が、外出や通院に困難を抱える重度の心身障害のある方等を対象に交付する区独自の移送支援制度です。区が契約するタクシー事業者または自動車燃料店で使える「移送サービス利用券」（200円券）を交付し、タクシー料金または自動車の燃料費（ガソリン代等）に充てることができます。対象や交付額は公式ページで確認してください。', '障害のある方が外出しやすいように、大田区がタクシー代やガソリン代に使える券（移送サービス利用券）を配る制度です。使える人や金額は決まっているので、公式ページや区役所の障害福祉課で確認してください。', 'service', '大田区内在住で、身体障害者手帳をお持ちの方のうち下肢・体幹機能障がい1～3級、移動機能障がい1～3級、視覚障がい1～2級、内部障がい1～2級のいずれかに該当する方、または愛の手帳1・2度をお持ちの方が対象となる可能性があります。特別養護老人ホーム入所者は対象外とされています。対象要件の詳細は必ず大田区公式ページや障害福祉課でご確認ください。', '交付額は年齢や所得区分により異なります。公式ページの記載では、65歳未満は1か月あたり200円券20枚（月額4,000円相当）、65歳以上は18枚（月額3,600円相当）、生活保護受給者は12枚（月額2,400円相当）、施設入所者は18枚で年度内2冊を限度とされています。最新の交付額・枚数は必ず公式ページでご確認ください。', NULL, '身体障害者手帳または愛の手帳を持参のうえ、大田区の障害福祉課または地域福祉課の窓口で申請します。詳しい手続きや必要書類は事前に障害福祉課（電話03-5744-1251）または公式ページでご確認ください。', NULL, FALSE, '大田区 障害福祉課', '03-5744-1251', NULL, 'https://www.city.ota.tokyo.jp/seikatsu/fukushi/shougai/seikatsushien/seikatsuken/seikatsuken/fukushi.html', '大田区ホームページ：福祉タクシー・自動車燃料費（移送サービス利用券）', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'onlineApplicationAvailable']::text[], '本情報は2026年6月24日時点の大田区公式ページに基づく概要です。対象要件・交付額・申請方法は変更される場合があります。実際の対象可否や手続きは、必ず大田区障害福祉課または公式ページでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
