insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'shibuya'), 'tokyo-shibuya-welfare-taxi', '渋谷区 福祉タクシー券の交付・自動車燃料費助成', '渋谷区では、歩行が困難な重度の心身障がいのある方（児）の外出・通院など日常生活の利便を図るため、福祉タクシー券の交付、または自動車燃料費（ガソリン・軽油など）の助成を行っています。両制度はいずれか一方のみの利用となり、重複して申し込むことはできません。対象や交付内容は公式ページでご確認ください。', '渋谷区では、重い障がいがあって歩くことが難しい方の外出や通院を支えるため、タクシー料金に使える「福祉タクシー券」を配るか、自家用車のガソリン代などの一部を助成しています。どちらか一方を選んで利用する制度で、両方を同時に申し込むことはできません。対象になるかどうかや金額は、区の障がい者福祉課（給付係）に問い合わせるか、公式ページでご確認ください。', 'service', '区内在住で、身体障害者手帳1・2級、身体障害者手帳3級のうち下肢・体幹機能障がいまたは酸素吸入装置を常時携帯する必要のある呼吸器機能障がいのある方、愛の手帳1・2度、精神障害者保健福祉手帳1級などの方が対象となる可能性があります。歩行が困難な重度の心身障がいのある方（児）が想定されています。正確な対象範囲・等級は公式ページでご確認ください。', '福祉タクシー券は、申請月から1か月につき300円券9枚と100円券8枚が交付されると公式に案内されています。自動車燃料費助成は、月額3,270円に支給対象月数を乗じた金額が助成されると案内されています（申請は4月分から9月分は10月、10月分から3月分は4月に受け付けと案内）。福祉タクシー券と自動車燃料費助成は重複して申し込むことはできません。金額・枚数は変更される場合があるため、公式ページで最新情報をご確認ください。', '自動車燃料費助成は、4月分から9月分の申請を10月、10月分から3月分の申請を4月に受け付けると案内されています（年2回）。具体的な申請期間・支給時期は公式ページ・窓口でご確認ください。', '障がい者福祉課給付係の窓口、郵送、またはLINEで申請できると公式に案内されています。詳細・必要書類は窓口へお問い合わせのうえ、公式ページでご確認ください。', '障害者手帳など対象を確認できる書類が必要となる可能性があります。必要書類の詳細は障がい者福祉課給付係へお問い合わせのうえ、公式ページでご確認ください。', TRUE, '渋谷区 福祉部 障がい者福祉課 給付係（渋谷区役所本庁舎2階）', '03-3463-1924', 'https://www.city.shibuya.tokyo.jp/kenko/shogai-seikatsu/waribiki/waribiki.html', 'https://www.city.shibuya.tokyo.jp/kenko/shogai-seikatsu/waribiki/waribiki.html', '交通機関の割引 | 料金の割引・税の控除 | 渋谷区ポータル', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText', 'targetPeople']::text[], '本情報は2026-06-24時点で渋谷区公式ページを基に整理した参考情報です。対象者・交付額・枚数・申請期間などの詳細は変更される場合があります。最終的な可否や手続きは、必ず渋谷区障がい者福祉課給付係および公式ページでご確認ください。当サイトは申請の代行や受給の保証を行うものではありません。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
