insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot welfare-taxi import', '{"slug":"tokyo-shibuya-welfare-taxi","status":"published","title":"渋谷区 福祉タクシー券の交付・自動車燃料費助成","officialUrl":"https://www.city.shibuya.tokyo.jp/kenko/shogai-seikatsu/waribiki/waribiki.html","topic":"welfare-taxi"}'::jsonb, 'pilot:tokyo-shibuya-welfare-taxi:dG9reW8tc2hpYnV5YS13ZWxmYXJlLXRheGl85riL' from public.support_programs sp where sp.slug='tokyo-shibuya-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'nakano'), 'tokyo-nakano-welfare-taxi', '中野区 福祉タクシー利用券・リフト付福祉タクシー利用券・福祉ガソリン券', '中野区が、重度の身体障害・知的障害のある方等の外出・通院を支えるために実施している移動支援制度です。福祉タクシー利用券（タクシー料金の一部に充当できる利用券）、車いす・ストレッチャー利用者向けのリフト付福祉タクシー利用券、および自家用車の燃料費を助成する福祉ガソリン券の3種類があり、福祉タクシー利用券と福祉ガソリン券はいずれか一方を選んで利用する形が公式で案内されています。対象等級・交付内容・所得制限などの詳細は公式ページでご確認ください。', '中野区では、重い障害があって外出や通院に支援が必要な方のために、タクシー料金に使える「福祉タクシー利用券」や、自家用車のガソリン代を助成する「福祉ガソリン券」などを用意しています。タクシー券は1冊4,000円分、ガソリン券は1冊3,300円分が目安です。手帳の等級や所得などの条件があり、タクシー券とガソリン券はどちらか一方を選ぶ形です。区役所3階の窓口や、お近くのすこやか福祉センターで申請できます。', 'service', '中野区内に住む重度の身体障害・知的障害のある方等が対象となる可能性があります。公式ページでは、身体障害者手帳の下肢・体幹・移動機能障害1〜3級、視覚障害1〜2級、上肢機能障害1級、内部障害1〜2級、または愛の手帳（療育手帳）1〜2度の方で、一定の所得基準を満たす方が対象とされています。具体的な対象等級・所得制限の詳細は中野区公式で確認してください。', '公式ページによると、福祉タクシー利用券は1冊あたり300円券12枚＋100円券4枚＝計4,000円分、リフト付福祉タクシー利用券は車いす券（1冊8枚）またはストレッチャー券、福祉ガソリン券（燃料費助成）は1冊あたり1,100円券3枚＝計3,300円分とされています。金額・枚数は改定される場合があるため、最新額は公式でご確認ください。', '年度ごとに利用券が交付・発送される運用で、令和8年度分は2026年3月6日（金曜日）から順次、宅配便にて発送と案内されています。申請時期・有効期限の詳細は公式でご確認ください。', '区役所3階の障害者福祉相談窓口、または中部・北部・南部・鷺宮の各すこやか福祉センターで申請できると公式で案内されています。詳細・受付時間は中野区障害福祉課にご確認ください。', '公式ページでは申請に必要な書類が明示されていません。身体障害者手帳または愛の手帳（療育手帳）等が必要となる可能性があるため、必要書類は窓口・公式でご確認ください。', FALSE, '中野区 健康福祉部 障害福祉課', '03-3228-8956', NULL, 'https://www.city.tokyo-nakano.lg.jp/kenko_hukushi/syogai/taisyohinmokukakujyu/gaisyutsushien/fukushitaxiriyo.html', '福祉タクシー利用券およびリフト付福祉タクシー利用券及び福祉ガソリン券 | 中野区', '2026-06-24', 'high', ARRAY['targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '対象等級・所得制限・交付額・利用回数は制度改定により変わることがあり、本ページの内容は調査時点（2026年6月）の公式情報に基づく概括です。最新の正確な内容と自分が対象となるかどうかは、必ず中野区障害福祉課または公式ページでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
