insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot welfare-taxi import', '{"slug":"tokyo-nakano-welfare-taxi","status":"published","title":"中野区 福祉タクシー利用券・リフト付福祉タクシー利用券・福祉ガソリン券","officialUrl":"https://www.city.tokyo-nakano.lg.jp/kenko_hukushi/syogai/taisyohinmokukakujyu/gaisyutsushien/fukushitaxiriyo.html","topic":"welfare-taxi"}'::jsonb, 'pilot:tokyo-nakano-welfare-taxi:dG9reW8tbmFrYW5vLXdlbGZhcmUtdGF4aXzkuK3p' from public.support_programs sp where sp.slug='tokyo-nakano-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'suginami'), 'tokyo-suginami-welfare-taxi', '福祉タクシー利用券の交付・自動車燃料費の助成（杉並区）', '杉並区では、重度の障害のある方等の外出・通院を支えるため、福祉タクシー利用券の交付（公式情報では月額5,300円分を申請月から最大12か月分）を行っています。自動車を利用する方は、福祉タクシー券に代えて自動車の燃料費助成（公式情報ではガソリン1リットル50円・軽油1リットル30円、月62リットルを上限）を選ぶこともできます。対象となるかどうかや交付内容は公式ページで確認してください。', '障害のある方が外出や通院でタクシーを使うとき、料金の一部に使える「福祉タクシー利用券」を杉並区が交付しています。自動車を使う方は、タクシー券のかわりにガソリン代などの「燃料費助成」を選ぶこともできます。どちらか一方を選びます。自分が対象になるか、いくらもらえるかは杉並区の公式ページで確認してください。', 'service', '公式情報によると、身体障害者手帳1～3級の下肢・体幹・内部障害など移動機能障害の方、身体障害者手帳1～2級の視覚障害の方、愛の手帳1～2度（重度心身障害者手当受給者は3度まで）の方、精神障害者保健福祉手帳1級の方などが対象となる可能性があります。対象となる障害種別・等級の詳細や、燃料費助成の前提となる自動車税等の減免要件は、必ず杉並区公式ページでご確認ください。', '公式情報では、福祉タクシー利用券は月額5,300円分を申請月から最大12か月分交付（500円・300円・100円券で精算し、メーター料金との差額は現金払い）。自動車燃料費助成はガソリン1リットルにつき50円・軽油1リットルにつき30円、ひと月62リットルを上限とされています。福祉タクシー券と燃料費助成はいずれか一方を選択します（公式ページに『福祉タクシー券を受けている方は燃料費助成を受けられません』と明記）。金額・上限は変更される場合があるため公式ページでご確認ください。', '公式情報によると、自動車燃料費助成は現況届の提出期限が6月30日、各年度の助成申請期限が翌年度の6月末とされています。福祉タクシー利用券の申請期限についての明記は確認できませんでした。最新の期限は公式ページでご確認ください。', '公式情報によると、福祉タクシー利用券・燃料費助成とも、保健福祉部障害者施策課障害者手当・医療係の窓口または郵送で申請できます。自動車燃料費助成については、区の電子申請サービス（オンライン）で提出できるのは現況届のみで、助成申請そのものは窓口または郵送によるとされています。詳しい手続きは公式ページでご確認ください。', '公式情報では、受給資格認定申請書、障害者手帳（郵送時はコピー）などが必要とされています。燃料費助成では自動車税減免決定通知書（または車検証・運転免許証・通院等の目的を示す書類の組み合わせ）も挙げられています。代理人申請の場合は委任状と代理人の本人確認資料が必要です。必要書類は公式ページでご確認ください。', TRUE, '杉並区 保健福祉部障害者施策課 障害者手当・医療係', '03-5307-0781', 'https://www.city.suginami.tokyo.jp/normalife/gaishutsu/taxi/index.html', 'https://www.city.suginami.tokyo.jp/s036/7963.html', '福祉タクシー利用券の交付｜杉並区公式ホームページ', '2026-06-24', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本ページは杉並区公式サイトの情報をもとにした概要です。対象要件・金額・上限・申請期限などは変更される場合があり、また個別の判定は区の審査によります。最新かつ正確な内容は必ず杉並区公式ページおよび障害者施策課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
