insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot welfare-taxi import', '{"slug":"tokyo-suginami-welfare-taxi","status":"published","title":"福祉タクシー利用券の交付・自動車燃料費の助成（杉並区）","officialUrl":"https://www.city.suginami.tokyo.jp/s036/7963.html","topic":"welfare-taxi"}'::jsonb, 'pilot:tokyo-suginami-welfare-taxi:dG9reW8tc3VnaW5hbWktd2VsZmFyZS10YXhpfOem' from public.support_programs sp where sp.slug='tokyo-suginami-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'toshima'), 'tokyo-toshima-welfare-taxi', '福祉タクシー券の交付（豊島区）', '豊島区が外出や通院を支えるために、重度の身体障害・知的障害のある方等を対象に交付している区独自の福祉タクシー券制度です。対象となる可能性があるのは、身体障害者手帳の下肢障害4級・下肢1〜3級・体幹機能障害1〜3級・視覚障害1〜2級・内部障害1〜3級、または愛の手帳1〜2度をお持ちの方で、いずれも公式ページで要件が定められています。交付額は障害区分により年額が異なります（公式で確認）。なお、同区の自動車燃料費助成とは併給できず、いずれか一方の利用となります。', '障害のある方の外出や通院を助けるため、豊島区がタクシーの料金に使える「福祉タクシー券」を交付する制度です。身体障害者手帳や愛の手帳をお持ちの方が対象となる可能性があります。代わりに車のガソリン代を助成する制度（自動車燃料費助成）もありますが、両方を同時に受けることはできません。詳しくは豊島区の障害福祉課にお問い合わせください。', 'service', '豊島区内に住所があり、身体障害者手帳（下肢障害4級、下肢1〜3級、体幹機能障害1〜3級、視覚障害1〜2級、内部障害1〜3級）または愛の手帳1〜2度をお持ちの方が対象となる可能性があります。令和8年度からは生活保護受給世帯の方も対象に加わると公式で案内されています。自動車燃料費助成を受けている方、施設入所中・長期入院中の方は対象外とされています。実際の対象可否・等級は必ず豊島区公式および障害福祉課でご確認ください。', '障害区分により年額が異なります。下肢障害4級の方は年額24,000円分（令和7年度までは21,600円分）、下肢1〜3級・体幹機能障害1〜3級・視覚障害1〜2級・内部障害1〜3級、愛の手帳1〜2度の方は年額44,400円分（令和7年度までは39,600円分）と公式に記載されています。1回に使用する枚数に制限はないとされています。最新の金額は公式でご確認ください。', NULL, '豊島区障害福祉課で申請します。窓口で受け取る際は身体障害者手帳または愛の手帳を持参するよう案内されています（代理人受取の場合は委任状等が必要）。令和8年度分は郵送を希望する対象者へ発送される旨の案内があります。具体的な申請手続きの詳細は公式ページおよび障害福祉課でご確認ください。', '身体障害者手帳または愛の手帳（窓口受取時に持参）。代理人が受け取る場合は委任状または身元確認書類が必要と案内されています。詳細は公式でご確認ください。', FALSE, '豊島区 障害福祉課', '03-4566-2442', 'https://www.city.toshima.lg.jp/203/kenko/shogai/shienjigyo/015824.html', 'https://www.city.toshima.lg.jp/203/kenko/shogai/shienjigyo/015824.html', '福祉タクシー券の交付 - 豊島区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationMethodText', 'requiredDocumentsText', 'onlineApplicationAvailable']::text[], '本ページは豊島区公式情報をもとにした概要です。対象要件・交付額・利用条件は変更される場合があり、また個別の事情により対象とならないこともあります。申請の可否や最新の取扱いは必ず豊島区公式ページおよび障害福祉課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
