insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot welfare-taxi import', '{"slug":"tokyo-toshima-welfare-taxi","status":"published","title":"福祉タクシー券の交付（豊島区）","officialUrl":"https://www.city.toshima.lg.jp/203/kenko/shogai/shienjigyo/015824.html","topic":"welfare-taxi"}'::jsonb, 'pilot:tokyo-toshima-welfare-taxi:dG9reW8tdG9zaGltYS13ZWxmYXJlLXRheGl856aP' from public.support_programs sp where sp.slug='tokyo-toshima-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'kita'), 'tokyo-kita-welfare-taxi', '北区 福祉タクシー券・ガソリン券（自動車燃料費助成）', '東京都北区が、歩行や外出が困難な在宅の心身障害者等の通院・外出を支えるために設けている移動支援制度です。一定の障害者手帳を持つ方には、タクシー料金に使える福祉タクシー券（月額500円券7枚と100円券5枚、月額4,000円分）が交付される可能性があります。自家用車を利用し自動車税・軽自動車税の減免を受けている方で福祉タクシー券の交付を受けていない方には、代わりに月額3,500円のガソリン券（自動車燃料費の助成）が交付される可能性があります。福祉タクシー券とガソリン券は併給できず、いずれかを選ぶ仕組みです。対象となる障害種別・等級、所得制限、交付額などの詳細は北区公式サイトおよび障害福祉課でご確認ください。', '足が不自由など外出がむずかしい障害のある方が、タクシー代やガソリン代に使える券を北区からもらえる場合がある制度です。タクシー券かガソリン券のどちらか一方を選んで使います。', 'service', '北区内に住む在宅の心身障害者等で、身体障害者手帳（下肢・体幹機能障害1〜3級、視覚障害1・2級、内部機能障害1〜3級）、愛の手帳1・2度、精神障害者保健福祉手帳1級などに該当する方が対象となる可能性があります。ガソリン券は自動車税または軽自動車税の減免を受け、福祉タクシー券の交付を受けていない方が対象となる可能性があります。いずれも所得制限があり、詳細な対象等級・限度額は公式でご確認ください。', '福祉タクシー券は1か月あたり500円券7枚と100円券5枚（月額4,000円分。公式で確認）。ガソリン券（自動車燃料費の助成）は月額3,500円（公式で確認）。福祉タクシー券とガソリン券は併給不可で、いずれか一方の利用となる可能性があります。', '年度途中の申請の場合、申請月から当該年度3月までの分を一括交付する取扱いがあるとされています（公式で確認）。詳細な締切は北区公式サイトでご確認ください。', '窓口での申請が基本です。障害者手帳、マイナンバーカード（または通知カード）等を持参して、北区福祉部障害福祉課（王子障害相談係・赤羽障害相談係）で申請します。ガソリン券の場合は自動車税減免決定通知書または軽自動車税減免通知書、対象の手帳、（北区へ転入した方は前住所地の住民税課税・非課税証明書）が必要です。申請方法・必要書類の詳細は公式で確認してください。', '福祉タクシー券：障害者手帳（身体障害者手帳または愛の手帳）、マイナンバーカードまたは通知カード、代理申請の場合は代理人の本人確認書類。ガソリン券：自動車税減免決定通知書または軽自動車税減免通知書、身体障害者手帳・愛の手帳・戦傷病者手帳のいずれか、北区へ転入した方は前住所地の住民税課税（非課税）証明書。', FALSE, '北区 福祉部 障害福祉課（王子障害相談係・赤羽障害相談係）', '03-3908-9081（王子障害相談係）／03-3903-4161（赤羽障害相談係）', NULL, 'https://www.city.kita.lg.jp/socialcare-health/disabilities/1008816/1008803/1008807.html', '福祉タクシー券｜東京都北区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'applicationDeadlineText', 'targetPeople']::text[], '本ページは北区公式サイトの情報をもとにまとめた概要です。対象となる障害等級・所得制限・交付額・利用方法は変更されることがあり、実際に受けられるかは審査・確認が必要です。最新かつ正確な内容は北区障害福祉課または公式サイトでご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
