insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot welfare-taxi import', '{"slug":"tokyo-kita-welfare-taxi","status":"published","title":"北区 福祉タクシー券・ガソリン券（自動車燃料費助成）","officialUrl":"https://www.city.kita.lg.jp/socialcare-health/disabilities/1008816/1008803/1008807.html","topic":"welfare-taxi"}'::jsonb, 'pilot:tokyo-kita-welfare-taxi:dG9reW8ta2l0YS13ZWxmYXJlLXRheGl85YyX5Yy6' from public.support_programs sp where sp.slug='tokyo-kita-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'arakawa'), 'tokyo-arakawa-welfare-taxi', '荒川区 福祉タクシー利用券／自動車燃料費の助成（障害者の移動支援）', '荒川区が、外出が困難な障がいのある方の通院・社会参加を支えるため、福祉タクシー利用券の交付（移動支援）、または自動車燃料費（ガソリン費等）の助成を行う区独自制度です。いずれか一方を選択する形で、両方を同時に受けることはできません。対象や交付額は公式サイトで確認してください。', '重い身体・知的障がいなどで外出が難しい方の通院やお出かけを助けるため、荒川区がタクシー利用券を渡す制度と、自家用車のガソリン代を一部助成する制度を用意しています。どちらか一方を選んで利用します。対象になるかどうか、券の枚数や助成額は区の公式ページや障害者福祉課で確認してください。', 'service', '荒川区内に住所があり、身体障害者手帳(下肢・体幹機能障がい1〜3級、視覚障がい1〜2級、上肢機能障がい1級、内部障がい1〜3級)または愛の手帳(1〜2度)をお持ちの方などが対象となる可能性があります。詳しい対象要件は荒川区公式サイトで確認してください。福祉タクシー券と自動車燃料費助成は併給できず、どちらか一方の選択となります。', '福祉タクシー利用券は、年度当初(おおむね4月)の新規申請で1冊11,700円分を4冊交付、5月以降の申請では1冊3,900円分を申請月から翌年3月分まで交付（公式サイトで確認）。自動車燃料費の助成は3ヶ月あたり10,500円を限度として助成（公式サイトで確認）。金額・冊数は年度により変わる可能性があります。', '申請時期により交付内容が異なります(年度当初の新規申請と5月以降の申請で交付額・対象期間が変わります)。詳細・締切は公式サイトで確認してください。', '福祉タクシー利用券は郵送または窓口で申請します。自動車燃料費の助成は公式サイトから申請書をダウンロードして提出します。いずれも荒川区福祉部障害者福祉課が窓口です。最新の手続きは公式サイトで確認してください。', '福祉タクシー利用券: 申請書、印鑑、身体障害者手帳または愛の手帳、(必要な場合)所得証明書。自動車燃料費の助成: 身体障害者手帳または愛の手帳、車検証のコピーまたは自動車税減免決定通知書、運転される方の運転免許証のコピー、印鑑、口座を確認できるもの。詳細は公式サイトで確認してください。', FALSE, '荒川区 福祉部障害者福祉課（福祉タクシー:相談支援係／自動車燃料費:障害サービス係）', '03-3802-3111', 'https://www.city.arakawa.tokyo.jp/a030/shougaisha/shien/taxishinsei.html', 'https://www.city.arakawa.tokyo.jp/a030/shougaisha/shien/taxishinsei.html', '福祉タクシー／荒川区公式サイト', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は荒川区公式サイト(確認日2026-06-24)に基づく概要です。対象要件・交付額・申請方法は変更される場合があります。受給の可否は審査により決まり、必ず受給できるものではありません。最新かつ正確な内容は必ず荒川区公式サイトおよび障害者福祉課でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
