insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot welfare-taxi import', '{"slug":"tokyo-arakawa-welfare-taxi","status":"published","title":"荒川区 福祉タクシー利用券／自動車燃料費の助成（障害者の移動支援）","officialUrl":"https://www.city.arakawa.tokyo.jp/a030/shougaisha/shien/taxishinsei.html","topic":"welfare-taxi"}'::jsonb, 'pilot:tokyo-arakawa-welfare-taxi:dG9reW8tYXJha2F3YS13ZWxmYXJlLXRheGl86I2S' from public.support_programs sp where sp.slug='tokyo-arakawa-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'itabashi'), 'tokyo-itabashi-welfare-taxi', '福祉タクシー券・自動車燃料券の交付（板橋区）', '板橋区が、歩行が困難な重度の障害のある区内在住の方等を対象に、外出・通院などの社会参加を支えるため、福祉タクシー券または自動車燃料券を交付する障害福祉の制度です。タクシー利用料金の一部に充てられる利用券、または自家用車のガソリン代に充てられる燃料券のいずれかが交付されます。対象となる障害の種別・等級、交付額や利用方法は公式ページで確認してください。', '板橋区が、歩行が困難な重度の障害のある方の外出や通院を助けるために、タクシー代に使える利用券、または自家用車のガソリン代に使える燃料券のどちらかを交付する制度です。タクシー券と燃料券はどちらか一方を選びます。年に2回、まとめて券が郵送されます。対象になるかどうかや申請方法は、板橋区の障がいサービス課に確認してください。', 'service', '公式によると、板橋区内に在住し歩行が困難な障害のある方が対象となる可能性があります。具体的には、下肢・体幹障害1級、上肢障害1～2級、視覚障害1～2級、内部障害1級、愛の手帳（知的障害）1～2度等、戦傷病者手帳の所持者、歩行困難な区指定難病・脳性まひ・進行性筋萎縮症の方などが対象として案内されています。施設入所中の方や一定以上の所得がある方は対象外となる場合があります。対象の詳細・該当の可否は必ず板橋区公式ページおよび障がいサービス課でご確認ください。', '公式案内では、福祉タクシー券は月額で、障害の程度に応じて500円券8枚＋100円券10枚（合計5,000円分）または500円券7枚＋100円券10枚（合計4,500円分）を限度に交付するとされています。自動車燃料券は月額で500円券6枚（合計3,000円分）を限度に交付するとされています。タクシー券と燃料券は通常いずれか一方を選択します。交付額・枚数や区分は区の要綱改定等により変わる可能性があるため、最新の額と該当区分は公式でご確認ください。', '公式によると、利用券は年2回（4月・10月）に6か月分をまとめて送付されます。タクシー券と燃料券の変更を希望する場合は、変更を希望する月の3か月前までに連絡が必要とされています。詳細は公式でご確認ください。', '公式によると、個人番号・身元が確認できるものと障害者手帳等を持参のうえ、板橋区福祉部 障がいサービス課 障がい相談係で申請します。自動車燃料券を希望する場合は自動車検査証（車検証）の写しも必要とされています。交付は原則として年2回（4月・10月）に6か月分をまとめて送付されます。申請方法・必要書類の詳細は公式ページでご確認ください。', '公式案内では、個人番号および身元が確認できるもの、障害者手帳等（身体障害者手帳・愛の手帳・戦傷病者手帳など）が必要とされています。自動車燃料券を希望する場合は自動車検査証（車検証）の写しも必要です。詳細は公式ページおよび障がいサービス課でご確認ください。', FALSE, '板橋区 福祉部 障がいサービス課 障がい相談係', '03-3579-2362', 'https://www.city.itabashi.tokyo.jp/kenko/shogai/shien/sanka/1003256.html', 'https://www.city.itabashi.tokyo.jp/kenko/shogai/shien/sanka/1003256.html', '福祉タクシー券・自動車燃料券の交付｜板橋区公式ホームページ', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本ページは公的支援制度の概要をわかりやすくまとめた参考情報です。対象の可否・交付額・申請方法などは制度改定により変わることがあります。最新かつ正確な内容と該当の可否は、必ず板橋区公式ページおよび障がいサービス課（03-3579-2362）でご確認ください。介護保険の介護タクシー（通院等乗降介助）とは別の制度です。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
insert into public.support_program_categories (support_program_id, category_id) select sp.id, c.id from public.support_programs sp, public.categories c where sp.slug = 'tokyo-itabashi-welfare-taxi' and c.slug = 'disability' on conflict do nothing;
