insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'nerima'), 'tokyo-nerima-welfare-taxi', '福祉タクシー・心身障害者自動車燃料費（ガソリン代）助成（練馬区）', '練馬区が、重度の身体・知的・精神障害のある方の外出や通院を支えるために行っている移動支援制度です。区と契約したタクシー事業者で使える福祉タクシー券（1か月につき3,500円分）の交付か、自動車を所有する方への燃料費（ガソリン代）助成のいずれか一方を、対象者が選んで利用できる可能性があります。福祉タクシー券と燃料費助成は併用できず、どちらか一方の利用となります。対象となる障害種別・等級や交付・助成の額は公式ページでご確認ください。', '練馬区では、重い障害のある方が外出や通院をしやすいように、タクシー代に使える券（1か月3,500円分）をもらえる制度があります。車を持っている方は、券のかわりにガソリン代の助成を選ぶこともできます。券とガソリン代助成は同時には使えず、どちらか一方です。対象になるかどうかは障害の種類や等級によるので、区の窓口で確認してください。', 'service', '公式ページによると、身体障害者手帳の障害種別が下肢・体幹・移動機能・視覚・内部障害で1〜3級の方、愛の手帳1・2度の方、精神障害者保健福祉手帳1級の方が対象となる可能性があります（燃料費助成は、これらの障害のある方と同居し生計を同じくする方が車両所有者である場合も対象となる可能性があります）。なお、原則として65歳以上の新規申請の方は対象外とされています。福祉タクシー券と自動車燃料費助成は併用できません。対象等級・年齢要件の詳細は必ず練馬区公式でご確認ください。', '福祉タクシー券は1か月につき3,500円分（500円券6枚と100円券5枚）が交付されます。自動車燃料費助成は公式ページの記載によると月額2,800円で、年3回（9月・1月・5月頃）に4か月分をまとめて車両所有者の指定口座へ振り込まれるとされています。金額・枚数・振込時期は変更される場合があるため、最新の交付額は公式でご確認ください。', '公式ページに明確な申請期限の記載は確認できませんでした。詳細は窓口にお問い合わせください。', '必要書類を用意し、お住まいの地域（郵便番号）を担当する総合福祉事務所の福祉事務係の窓口で申請します（代理申請も可能とされています）。精神障害のある方は健康部保健予防課精神保健係が窓口です。申請の可否や手続きの詳細は窓口にお問い合わせください。', '身体障害者手帳・愛の手帳・精神障害者保健福祉手帳のいずれか（該当するもの）。自動車燃料費助成を申請する場合は、加えて対象となる車の車検証の写しと、車両所有者の口座番号がわかるものが必要とされています。代理申請の場合は代理人の身分証明書の写しが必要な場合があります。', FALSE, '練馬区 各総合福祉事務所 福祉事務係（精神障害の方は健康部保健予防課精神保健係）', '03-5984-4612（練馬総合福祉事務所）／03-5393-2817（石神井）／03-5905-5274（大泉）／03-5997-7060（光が丘）／03-5984-4764（保健予防課精神保健係）', 'https://www.city.nerima.tokyo.jp/hokenfukushi/shogai/nichijo/jidosha/fukushi_taxi.html', 'https://www.city.nerima.tokyo.jp/hokenfukushi/shogai/nichijo/jidosha/fukushi_taxi.html', '福祉タクシー：練馬区公式ホームページ', '2026-06-24', 'high', ARRAY['applicationDeadlineText', 'targetPeople']::text[], '本情報は練馬区公式ホームページ（2026-06-24時点）にもとづく概要です。対象要件・金額・手続きは変更される場合があり、申請により必ず交付・助成を受けられることを保証するものではありません。最終的なご判断の前に必ず公式ページおよび区の窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
