insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'adachi'), 'tokyo-adachi-welfare-taxi', '福祉タクシー・自動車燃料助成券の交付（足立区）', '足立区が、外出が困難な身体・知的障がいのある方を対象に、年1回「福祉タクシー・自動車燃料助成券」を交付する制度です。区と契約するタクシーの乗車料金や、区指定ガソリンスタンドでの給油料金の支払いに利用できる可能性があります。対象となる手帳の種類・等級、交付冊数・金額や利用方法は公式ページでご確認ください。', '障がいのある方の外出や通院を支えるため、タクシー代やガソリン代に使える助成券を年1回受け取れる可能性がある足立区独自の制度です。対象や金額は手帳の種類・等級によって異なるため、まず公式ページと窓口でご確認ください。', 'service', '足立区内に住所があり、身体障害者手帳または愛の手帳を所持する方のうち、所定の障がい等級に該当する方が対象となる可能性があります。詳細は公式ページでご確認ください。', '年1回交付。申請月に応じて、4月〜7月=3冊(42,000円分)、8月〜11月=2冊(28,000円分)、12月〜3月=1冊(14,000円分)。1冊14,000円分(500円券24枚＋100円券20枚)とされています（金額・冊数は変更される場合があるため公式で要確認）。', '定期的な申請期限は公式ページに明記されていません。年度途中の新規申請や詳細は窓口・公式ページでご確認ください。', '障がい福祉課障がい給付係（本庁舎北館1階）の窓口、またはオンライン申請（マイナンバーカードとスマートフォンが必要）で申請できるとされています。更新申請は不要で、継続該当者には3月末頃に新年度分が簡易書留で郵送されると案内されています。最新の手続きは公式ページでご確認ください。', '身体障害者手帳または愛の手帳。ガソリンスタンドで給油に利用する場合は車検証または標識交付証明書が必要とされています。', TRUE, '足立区 福祉部 障がい福祉課 障がい給付係', '03-3880-5472', 'https://www.city.adachi.tokyo.jp/shogai/20220301.html', 'https://www.city.adachi.tokyo.jp/shogai/20220301.html', '福祉タクシー・自動車燃料助成券の交付｜足立区', '2026-06-24', 'high', ARRAY['benefitAmountText', 'targetPeople', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本情報は2026-06-24時点で足立区公式サイトを確認して作成した概要です。対象等級・交付額・利用方法・申請手続きは変更される場合があります。実際の申請可否や金額は、必ず足立区の公式ページおよび担当窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
