insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot welfare-taxi import', '{"slug":"tokyo-adachi-welfare-taxi","status":"published","title":"福祉タクシー・自動車燃料助成券の交付（足立区）","officialUrl":"https://www.city.adachi.tokyo.jp/shogai/20220301.html","topic":"welfare-taxi"}'::jsonb, 'pilot:tokyo-adachi-welfare-taxi:dG9reW8tYWRhY2hpLXdlbGZhcmUtdGF4aXznpo/n' from public.support_programs sp where sp.slug='tokyo-adachi-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.support_programs (municipality_id, slug, title, summary, plain_language_summary, benefit_type, target_people, benefit_amount_text, application_deadline_text, application_method_text, required_documents_text, online_application_available, contact_name, contact_phone, contact_url, official_url, official_source_title, last_official_checked_at, source_confidence, uncertain_fields, disclaimer_note, status, published_at, updated_at) values ((select m.id from public.municipalities m join public.prefectures pr on pr.id = m.prefecture_id where pr.slug = 'tokyo' and m.slug = 'edogawa'), 'tokyo-edogawa-welfare-taxi', '福祉タクシー券・自動車燃料費助成（江戸川区）', '江戸川区では、歩行が困難な在宅の障害のある方の外出を支援するため、福祉タクシー券を交付しています（公式では半年に1回6冊／1か月1冊3,000円分とされています）。また、日常生活で自動車を利用する障害のある方には、燃料費を月額上限3,000円まで助成する制度があります。福祉タクシー券と自動車燃料費助成は選択制です。対象となる障害の種別・等級や交付額・回数は公式ページでご確認ください。', '車いすなどで歩くのが難しい障害のある方が、タクシーで外出しやすいように、江戸川区がタクシー券を配る制度です。自分や家族の車で出かける方には、ガソリン代を一部助成する別の制度もあります。この二つはどちらか一方を選んで使う仕組みです。どちらが使えるかは障害の種類や程度によって変わります。まずは区の障害者福祉課に相談してみましょう。', 'service', '公式によると、福祉タクシー券は身体障害者手帳1～3級の下肢・体幹・移動機能障害、1～2級の視覚障害、1級の内部障害、3級の呼吸器障害で外出時に携帯酸素を利用する方、愛の手帳1～2度の方などで、タクシーを利用しなければ移動が困難な方が対象となる可能性があります。自動車燃料費助成は障害の種別・等級により対象が一部異なり、上肢1～2級は本人運転のみ、視覚障害・愛の手帳は介護者運転のみといった条件が付く場合があります。詳細・該当可否は公式ページおよび窓口でご確認ください。', '公式によると、福祉タクシー券は半年に1回6冊（1か月1冊3,000円分）が交付されます。自動車燃料費助成は月額上限3,000円まで（給油のない月は対象外）とされています。具体的な交付額・利用回数は公式でご確認ください。', '福祉タクシー券は半年に1回の更新申請が必要で、公式では2月・8月に申請するとされています。詳細は公式でご確認ください。', '公式によると、マイナポータルのぴったりサービスによる電子申請、窓口申請、郵送申請のいずれかで申請できます。福祉タクシー券は半年分ずつの交付のため、更新申請が半年に1回（2月・8月）必要とされ、交付（券の郵送）は3月下旬・9月下旬とされています。', '公式によると、身体障害者手帳または愛の手帳、印鑑（スタンプ印不可）、マイナンバー関係書類・身元確認書類などが必要です。自動車燃料費助成では加えて、運転する方の運転免許証、自動車検査証、本人名義の普通預金通帳などが必要とされています。最新の必要書類は公式でご確認ください。', TRUE, '江戸川区 福祉部障害者福祉課 自立援助係', '03-5662-0062', 'https://www.city.edogawa.tokyo.jp/e041/kenko/fukushikaigo/shogaisha/service/seikatsu/gaishutsu/taxi.html', 'https://www.city.edogawa.tokyo.jp/e041/kenko/fukushikaigo/shogaisha/service/seikatsu/gaishutsu/taxi.html', '福祉タクシー券 江戸川区ホームページ', '2026-06-24', 'high', ARRAY['targetPeople', 'benefitAmountText', 'applicationDeadlineText', 'requiredDocumentsText']::text[], '本ページは2026-06-24時点の江戸川区公式サイトの情報をもとにまとめた概要です。対象となる障害の種別・等級、交付額、利用回数、福祉タクシー券と燃料費助成の選択制などは変更されることがあり、最終的な該当可否は江戸川区の公式ページおよび窓口でご確認ください。', 'published', now(), now()) on conflict (slug) do update set municipality_id=excluded.municipality_id, title=excluded.title, summary=excluded.summary, plain_language_summary=excluded.plain_language_summary, benefit_type=excluded.benefit_type, target_people=excluded.target_people, benefit_amount_text=excluded.benefit_amount_text, application_deadline_text=excluded.application_deadline_text, application_method_text=excluded.application_method_text, required_documents_text=excluded.required_documents_text, online_application_available=excluded.online_application_available, contact_name=excluded.contact_name, contact_phone=excluded.contact_phone, contact_url=excluded.contact_url, official_url=excluded.official_url, official_source_title=excluded.official_source_title, last_official_checked_at=excluded.last_official_checked_at, source_confidence=excluded.source_confidence, uncertain_fields=excluded.uncertain_fields, disclaimer_note=excluded.disclaimer_note, status=excluded.status, published_at=case when excluded.status='published' and public.support_programs.published_at is null then excluded.published_at when excluded.status<>'published' then null else public.support_programs.published_at end, updated_at=excluded.updated_at;
insert into public.support_program_categories (support_program_id, category_id) select sp.id, c.id from public.support_programs sp, public.categories c where sp.slug = 'tokyo-edogawa-welfare-taxi' and c.slug = 'disability' on conflict do nothing;
