insert into public.support_revisions (support_program_id, change_type, change_summary, after_json, external_key) select sp.id, 'seed_import', 'pilot welfare-taxi import', '{"slug":"tokyo-edogawa-welfare-taxi","status":"published","title":"福祉タクシー券・自動車燃料費助成（江戸川区）","officialUrl":"https://www.city.edogawa.tokyo.jp/e041/kenko/fukushikaigo/shogaisha/service/seikatsu/gaishutsu/taxi.html","topic":"welfare-taxi"}'::jsonb, 'pilot:tokyo-edogawa-welfare-taxi:dG9reW8tZWRvZ2F3YS13ZWxmYXJlLXRheGl856aP' from public.support_programs sp where sp.slug='tokyo-edogawa-welfare-taxi' on conflict (external_key) where external_key is not null do nothing;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.chiyoda.lg.jp/koho/kenko/shogaisha/techo/josei/fukushitaxi.html', '敵対的検証完了（確認日2026-06-24）。officialUrl（https://www.city.chiyoda.lg.jp/koho/kenko/shogaisha/techo/josei/fukushitaxi.html）および燃料費助成ページ（.../j-nenryo.html）の両方をWebFetchで取得し、一次調査の全記載を照合した。(a)両URL到達可。(b)ホストwww.city.chiyoda.lg.jpは.lg.jp/city.*の許可ホスト。(c)千代田区自身の福祉タクシー券の当該区ページであることを確認。(d)最終更新2023-04-13で現行・受付終了記載なし。(e)障害福祉制度であり介護保険の介護タクシーとの混同なし（明記を確認）。(f)対象者は主要カテゴリを「など」「対象となる可能性」「公式・窓口で確認」と非断定で概括しており一部を全体と断定していない。(g)福祉タクシー券と自動車燃料費助成は同一移動支援枠の選択制（両ページで併用不可を明記）であり、別制度の無理な統合ではなく適切に1件として福祉タクシー券を主制度採用。(h)等級・交付額（4か月1冊1' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='chiyoda' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.chuo.lg.jp/a0023/kenkouiryou/shougaishafukushi/shienservice/seikatuken/takusir.html', '敵対的検証完了。一次調査は全チェック項目をクリアし是正不要でok=true。' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='chuo' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.minato.tokyo.jp/kenko/fukushi/shogaisha/shakaisanka/taxi.html', '検証完了。port officialUrl（taxi.html）および燃料費助成ページ（nenryohi.html）を両方WebFetchで到達確認。両URLとも許可ホストwww.city.minato.tokyo.jp（city.*/.tokyo.jp）に一致。両ページとも更新日2026-05-27・受付終了表示なし＝現行。(c)港区独自の障害福祉移動支援制度の当該区ページであることを確認。(e)介護タクシー（通院等乗降介助）との混同なし＝生活圏拡大・経済負担軽減目的の港区独自事業。(f)targetPeopleは「など」「公式で確認」でヘッジ済・uncertainFields記載。(g)タクシー利用券と自動車燃料費助成は同一移動支援枠の選択肢（明示的に併給不可）であり1件統合は妥当。(h)金額・等級は非断定でヘッジ済。【是正点】一次調査では電話番号「当該ページに記載なし」としていたが、taxi.htmlに各総合支所代表番号03-3578-2111（代表）の記載を確認したため、contactPhoneに追加しuncertainFieldsから除外。対象等級（身障手帳：下肢・体幹/視覚' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='minato' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.shinjuku.lg.jp/fukushi/file06_04_00022.html', '敵対的検証完了（2026-06-24）。program.officialUrl（https://www.city.shinjuku.lg.jp/fukushi/file06_04_00022.html）をWebFetchで実取得し、併記の燃料費助成ページ（file06_04_00023.html）も確認。検証結果: (a)到達=両ページとも生存。(b)許可ホスト=www.city.shinjuku.lg.jp（.lg.jp/city.*）一致。(c)当該区ページ=新宿区公式「心身障害者福祉タクシー券（福祉タクシー利用券）」本体ページで正しい。(d)現行性=タクシー券ページ最終更新2026-04-01・受付終了記載なし＝現行（燃料費助成ページは2023-04-01更新だが内容現行）。(e)国/都制度・介護タクシーとの混同なし=区独自の障害福祉移動支援制度として正しく記述。(f)対象の一部を全体と書く誤りなし=身体障害者手帳（下肢・体幹・移動機能・内部障害1〜3級、視覚1〜2級、平衡機能3級）/愛の手帳1〜2度＝公式と一致。(g)別制度の無理な統合なし=福祉タクシー券と燃料費助成は「併給不' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='shinjuku' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.bunkyo.lg.jp/b018/p003420.html', '敵対的検証完了（2026-06-24）。officialUrl（https://www.city.bunkyo.lg.jp/b018/p003420.html）をWebFetchで取得し、併記の自動車燃料費助成ページ（https://www.city.bunkyo.lg.jp/b018/p003422.html）も照合した。(a)両URL到達 (b)許可ホスト www.city.bunkyo.lg.jp（.lg.jp/city.*）一致 (c)文京区独自の福祉タクシー利用券交付制度の当該区ページであることを確認 (d)タクシー券ページは更新日2026-03-31・令和8年度事業者一覧掲載、燃料費助成ページは更新日2026-02-19、いずれも受付終了表示なく現行 (e)介護タクシー・国制度・都制度との混同なし、区独自制度と明記 (f)対象等級は概括＋「公式で確認」で部分を全体と書いていない (g)福祉タクシー券と自動車燃料費助成は併給不可の選択肢として同一移動支援の枠で扱われ、別制度の無理な統合ではない（登録はタクシー券ページを主とする） (h)「可能性があります」「公式で確認してくだ' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='bunkyo' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.taito.lg.jp/kenkohukusi/shogai/service/seikatuken/shaji/fukusitaxi.html', '検証完了（2026-06-24）。officialUrl（https://www.city.taito.lg.jp/kenkohukusi/shogai/service/seikatuken/shaji/fukusitaxi.html）をWebFetchで確認＝到達OK。(a)到達OK (b)許可ホスト合致＝www.city.taito.lg.jp は .lg.jp/city.* に該当 (c)台東区公式の福祉タクシー利用券の当該ページであることを確認 (d)古い年度/受付終了表示なし（燃料費助成ページは2025-10-01更新） (e)区独自制度で、国制度/都制度の一般説明や介護保険の介護タクシー（通院等乗降介助）との混同なし (f)対象等級は「など」で例示し全範囲をuncertainFieldsに退避＝一部を全体と誤記していない (g)福祉タクシー券と燃料費助成は併給不可の同一移動支援の選択肢（どちらか一方）であり、別制度の無理な統合ではない＝許容 (h)対象/金額は非断定で公式確認へ誘導。検証で判明した軽微な是正：福祉タクシー券の対象に内部機能障害（心臓・腎臓・呼吸器・膀胱・直腸' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='taito' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.sumida.lg.jp/kenko_fukushi/syougai/waribiki/taxi.html', '敵対的検証を実施。program.officialUrl（https://www.city.sumida.lg.jp/kenko_fukushi/syougai/waribiki/taxi.html）をWebFetchで取得し、以下を確認した。(a)到達=可。(b)許可ホスト=www.city.sumida.lg.jp（.lg.jp かつ city.*）で適合。FAQ専用ドメインではない。(c)墨田区公式の「心身障害者福祉タクシー料金・自動車燃料費助成共通券の交付」当該ページで一致。(d)更新日2026年4月1日・受付終了/過去年度の記載なし=現行。(e)国制度・都制度の一般説明ではなく区独自の共通券制度。介護保険の通院等乗降介助（介護タクシー）とは別物で混同なし。(f)対象等級（視覚1～2級、下肢・体幹/脳病変移動機能1～3級、内部1～2級、愛の手帳1～2度）は公式記載と一致し、targetPeopleは「など」「可能性があります」で概括しており部分を全体と断定していない。(g)タクシー料金助成と自動車燃料費（ガソリン）助成は同一の「共通券」という1つの移動支援制度の利用選択肢であり' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='sumida' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.koto.lg.jp/222015/fukushi/shogaisha/waribiki/jose/6708.html', '敵対検証完了（2026-06-24）。program.officialUrl（https://www.city.koto.lg.jp/222015/fukushi/shogaisha/waribiki/jose/6708.html）および燃料費助成URL（.../6779.html）の両方をWebFetchで実地確認。判定: (a)両URL到達OK (b)許可ホスト一致＝city.koto.lg.jp（.lg.jp公式） (c)いずれも江東区自身の福祉タクシー券/自動車燃料費助成の当該区ページ (d)更新日2026-05-11/2026-03-04・受付終了表示なし＝現行 (e)心身障害者向け福祉施策で介護保険の介護タクシーと混同なし (f)対象等級は公式記載と一致（身体1級〔視覚1・2級、下肢・体幹・移動1〜3級〕・愛の手帳1・2度） (g)福祉タクシー券と燃料費助成は同一移動支援スキームの選択肢で統合は妥当 (h)区差ある等級・額は概括＋公式確認の文言あり・断定なし。重要な是正点: 一次調査は両制度を「選択制（どちらか）」と記載していたが、公式は両ページとも明確に【併給不可】を明記' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='koto' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.shinagawa.tokyo.jp/PC/kenkou/kenkou-syogai/kenkou-syogai-seikatsuken/hpg000033560.html', '敵対的検証実施（2026-06-24）。program.officialUrl を WebFetch で再取得し一次調査と照合。(a)到達=OK。(b)許可ホスト=city.shinagawa.tokyo.jp（city.*＋.tokyo.jp）で品川区公式、FAQ専用ドメインではない=OK。(c)当該区の福祉タクシー・自動車燃料費助成そのもののページ=OK（タイトル「福祉タクシー・自動車燃料費助成券の交付」）。(d)現行=OK、ページ更新日「令和8年4月1日」を確認、古い年度・受付終了の記載なし。(e/g)介護タクシー・国都制度との混同なし=OK。本制度は障害福祉の助成券で、1つの助成券をタクシー利用料金または自動車燃料費に選択利用できる同一移動支援制度（別制度の無理な統合ではない）。ページ内に介護タクシー契約事業者一覧への言及はあるが本制度（障害福祉）とは区別される。(f)対象の一部を全体と誤記していない=OK、対象等級は概括＋「公式で確認」表現。(h)断定回避・非確定表現あり=OK。助成額の券種について公式は2パターン（500円券×6＋100円券×5、またはタクシー専用券不要時は' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='shinagawa' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.meguro.tokyo.jp/shougaishien/kenkoufukushi/shougaisha/fukusitakusii.html', '敵対的検証完了。一次調査の3 URLすべてをWebFetchで再確認し、内容を逐語照合した。(1) officialUrl https://www.city.meguro.tokyo.jp/shougaishien/kenkoufukushi/shougaisha/fukusitakusii.html は到達可（200）、許可ホスト www.city.meguro.tokyo.jp（.tokyo.jp / city.*）、FAQ専用ドメインでない。ページタイトル「福祉タクシー利用券の給付」で目黒区の当該区ページそのもの、最終更新2026-04-01・受付終了記載なし＝現行。(2) 燃料費助成ページ https://www.city.meguro.tokyo.jp/shougaishien/kenkoufukushi/shougaisha/jidousya_nenryou.html も到達可、タイトル「自動車燃料費の助成」、「月額2,500円を限度として4か月毎に給付」「福祉タクシー利用券との併給はできません」「施設に入所しているかた」「入院中のかた」は受給不可、必要書類に車検証の写し＝' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='meguro' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.ota.tokyo.jp/seikatsu/fukushi/shougai/seikatsushien/seikatsuken/seikatsuken/fukushi.html', '敵対的検証完了（2026-06-24）。program.officialUrl をWebFetchで2回取得し、一次調査の主要主張をすべて照合・確認した。検証結果：(a)到達=200・本文取得可。(b)許可ホスト=www.city.ota.tokyo.jp（.tokyo.jp＋city.*の公式許可ホスト。FAQ専用ドメインではない）。(c)当該区ページ=大田区独自の「福祉タクシー・自動車燃料費（移送サービス利用券）」ページで一致。(d)現行=ページ更新日2026年5月26日、受付終了/旧年度の記載なし。(e)誤認なし=「大田区が契約している」と明記され大田区独自制度。介護保険の介護タクシー（通院等乗降介助）の説明は当該ページに含まれず、混同していない。国・都制度の一般説明でもない。(f)対象の一部を全体化していない=対象等級（下肢・体幹1～3級/移動1～3級/視覚1～2級/内部1～2級、愛の手帳1・2度）を列挙し「公式で確認」と付し、特別養護老人ホーム入所者は対象外という公式文言（「なお、特別養護老人ホームに入所している方は交付対象外です」）も正しく反映。(g)複数制度の不当統合なし' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='ota' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.setagaya.lg.jp/02084/2758.html', '敵対検証完了（2026-06-24）。program.officialUrl（https://www.city.setagaya.lg.jp/02084/2758.html「福祉タクシー券の交付」）と関連の燃料費助成ページ（02084/2759.html「自動車燃料費の助成」）を独立にWebFetchで再取得し、一次調査の記載と照合した。検証結果: (a)両URL到達OK。(b)ホスト www.city.setagaya.lg.jp は .lg.jp かつ city.* で許可ホスト一致（FAQ専用ドメインではない）。(c)いずれも世田谷区公式の福祉タクシー券/燃料費助成そのものの当該区ページ。(d)現行（福祉タクシー券=最終更新2023-04-01、燃料費助成=最終更新2025-05-01、受付終了/廃止の記載なし）。(e)国制度・都制度の一般説明ではなく区独自制度。介護タクシー(訪問介護タクシー)との混同なし（介護タクシーの記載は無い）。(f)対象は身体障害者手帳(下肢・体幹・内部・平衡・脳性まひ等の運動機能障害1〜3級、視覚障害1・2級)または愛の手帳1・2度で、targetPe' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='setagaya' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.shibuya.tokyo.jp/kenko/shogai-seikatsu/waribiki/waribiki.html', '渋谷区公式（www.city.shibuya.tokyo.jp ＝許可ホスト city.*/.tokyo.jp）の「交通機関の割引｜料金の割引・税の控除」ページをWebFetchで2回検証（2026-06-24時点、ページ更新日2026-06-15・現行）。福祉タクシー券と自動車燃料費助成の両制度が当該区独自の障害福祉制度として記載されていることを原文で確認。福祉タクシー券＝「申請月から、1か月につき300円券9枚と100円券8枚を交付」、対象は「区内在住で自動車燃料費の助成を受けておらず」身体障害者手帳1・2級／3級のうち下肢・体幹機能障がいまたは酸素吸入装置を常時携帯する必要のある呼吸器機能障がい／愛の手帳1・2度／精神障害者保健福祉手帳1級。自動車燃料費助成＝「3,270円に支給対象月数を乗じた金額」を「4月分から9月分の申請は10月、10月分から3月分の申請は4月に受け付け」。両制度は重複申込不可（福祉タクシー券の条件に『自動車燃料費の助成を受けておらず』）。窓口は障がい者福祉課給付係（渋谷区役所本庁舎2階）、電話03-3463-1924、窓口・郵送・LINEで申請可。高齢者を' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='shibuya' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.tokyo-nakano.lg.jp/kenko_hukushi/syogai/taisyohinmokukakujyu/gaisyutsushien/fukushitaxiriyo.html', '敵対的検証完了（2026-06-24）。program.officialUrl を WebFetch で再取得し、一次調査の主張を逐一照合。(a)到達=OK（ページID 279065088、更新日2026-02-16）。(b)許可ホスト=www.city.tokyo-nakano.lg.jp（.lg.jp 公式、FAQ専用ドメインでない）でPASS。(c)中野区独自の福祉タクシー利用券・リフト付福祉タクシー利用券・福祉ガソリン券の当該区ページであることを本文で確認。(d)受付終了記載なし・令和8年度分の発送案内ありで現行。(e)国制度/都制度/介護タクシーとの混同なし（区独自の外出支援）。(f)対象を「対象となる可能性」「公式で確認」と概括し一部を全体と断定していない。(g)タクシー券・ガソリン券は「いずれか一方を選択し交付を受ける」と公式に明記＝同一移動支援制度の選択肢であり1件統合は妥当。(h)FORBIDDEN表現・断定なし、区差のある対象等級/交付額は概括＋「公式で確認」。照合結果：電話番号03-3228-8956は公式ページ本文で確定（検索スニペットの03-3228-8953' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='nakano' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.suginami.tokyo.jp/s036/7963.html', '敵対的検証を実施。officialUrl(7963.html)および燃料費助成ページ(7962.html)をWebFetchで再取得し全項目を突合。(a)両URLとも到達・本文取得可。(b)ホストwww.city.suginami.tokyo.jpはcity.*.tokyo.jpの公式許可ホストに一致。(c)7963.htmlは杉並区の福祉タクシー利用券交付、7962.htmlは杉並区の自動車燃料費助成で、いずれも当該区の当該制度ページ。(d)7963.htmlは更新日2025-12-02で現行。燃料費助成の現況届6/30・助成申請翌年度6月末は毎年度の通常サイクルで受付終了ではない。(e)区独自の障害者移動支援制度であり、介護保険の介護タクシー・国/都制度の一般説明との混同なし（一次調査でも確認済み）。(f)対象は代表的種別を概括し『など』＋公式確認誘導、uncertainFieldsに記載。(g)福祉タクシー券と燃料費助成は同一移動支援制度の選択肢で相互排他（公式に『福祉タクシー券を受けている方は受けられません』と明記）であり、規則上の統合可ケースに該当。(h)金額・対象等級は『公' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='suginami' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.toshima.lg.jp/203/kenko/shogai/shienjigyo/015824.html', '敵対的検証を実施し、一次調査の妥当性を確認しました（2026-06-24）。検証手順: (1) program.officialUrl（015824.html）をWebFetchで取得→到達確認。許可ホスト www.city.toshima.lg.jp（.lg.jp/city.* に合致、FAQ専用ドメインでない）。当該ページは豊島区独自の「福祉タクシー券の交付」ページそのもの。更新日2026-03-13で令和8年度内容を含み現行。(2) 自動車燃料費助成ページ（015827.html、更新日2026-03-09）も取得し併給不可を双方向で確認（タクシー券ページは燃料費助成受給者を除外、燃料費助成ページは福祉タクシー券交付者を除外）。\n\n各フィールドの公式照合結果: 交付額=下肢4級 令和8年度24,000円分/令和7年度まで21,600円、その他対象・愛の手帳1〜2度 44,400円分/令和7年度まで39,600円——公式記載と完全一致。対象=身体障害者手帳（下肢4級、下肢1〜3級、体幹機能障害1〜3級、視覚障害1〜2級、内部障害1〜3級）・愛の手帳1〜2度、令和8年度分から生活' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='toshima' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.kita.lg.jp/socialcare-health/disabilities/1008816/1008803/1008807.html', '敵対的検証(2026-06-24)を実施。(a)到達: program.officialUrl(福祉タクシー券)とガソリン券ページ(1008784/1008790/1008796)の両方をWebFetchで取得成功。(b)許可ホスト: www.city.kita.lg.jp は .lg.jp かつ city.* で許可ホスト一致。(c)当該区ページ: 北区公式の福祉タクシー券(障害福祉)制度ページと自動車燃料費助成ページであることを本文で確認。(d)現行性: 両ページとも更新日2026年4月1日と明記、受付終了/旧年度の記載なし。(e)国/都制度誤認・介護タクシー混同なし: 北区独自の障害福祉制度であり、介護保険の介護タクシーではないことをページ本文で確認。(f)対象の一部を全体化していない: targetPeopleは「など」「可能性があります」で概括。(g)複数制度の無理な統合なし: 福祉タクシー券とガソリン券は『福祉タクシー券の交付を受けていない方』が燃料費助成の対象=併給不可の択一であることを公式本文で確認、同一移動支援の選択肢として統合は妥当。(h)非断定: 区差のある対象等' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='kita' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.arakawa.tokyo.jp/a030/shougaisha/shien/taxishinsei.html', '敵対的検証完了（検証日2026-06-24）。一次調査の2つの公式ページをWebFetchで再取得し全項目を照合。(a)両URL到達可。(b)ホストwww.city.arakawa.tokyo.jpは荒川区公式の許可ホスト(city.*/.tokyo.jp)。FAQ専用ドメイン等の非公式は不使用。(c)いずれも荒川区障害者福祉課所管の当該区の福祉タクシー券/自動車燃料費助成ページそのもの。(d)現行:福祉タクシーページ最終更新2026-04-06、燃料費ページ2025-05-19、いずれも受付終了でない。(e)国制度/都制度や介護保険の介護タクシーとの誤認なし(研究ノートで明示的に区別)。(f)対象等級は公式と完全一致(身体:下肢・体幹1〜3級/視覚1〜2級/上肢1級/内部1〜3級、愛の手帳1〜2度)で「など」「公式で確認」と概括、一部を全体と断定せず。(g)福祉タクシー券と燃料費助成は併給不可の選択肢で同一移動支援の枠内—公式両ページが相互排他を明記しており統合は妥当(別制度の無理な統合ではない)。(h)変動しうる交付額・対象・締切・必要書類は全てuncertainFieldsに記載' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='arakawa' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.itabashi.tokyo.jp/kenko/shogai/shien/sanka/1003256.html', '敵対的検証を実施。program.officialUrl（https://www.city.itabashi.tokyo.jp/kenko/shogai/shien/sanka/1003256.html）をWebFetchで実機確認（確認日2026-06-24）。検証結果: (a)到達=OK。(b)許可ホスト=www.city.itabashi.tokyo.jp は city.*/.tokyo.jp パターンに一致、FAQ専用ドメインではない=OK。(c)当該区の福祉タクシー券/燃料券ページ=タイトル『福祉タクシー券・自動車燃料券の交付』、板橋区『障がい者の社会参加』カテゴリ=OK。(d)現行制度=『令和4年度からハガキでの申請手続きが不要となりました』と明記、受付終了・旧年度ではない=OK。(e)国/都の一般説明や介護保険の介護タクシー（通院等乗降介助）との混同なし=公式が『障がい福祉』制度と明示=OK。(f)対象を一部のみで全体と誤記していない（『等』で概括＋公式確認誘導）=OK。(g)複数別制度の無理な統合なし（タクシー券・燃料券は同一移動支援制度内の選択肢）=OK。(h)FOR' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='itabashi' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.nerima.tokyo.jp/hokenfukushi/shogai/nichijo/jidosha/fukushi_taxi.html', '検証完了（2026-06-24）。officialUrl（福祉タクシーページ）と燃料費助成ページの両方をWebFetchで取得・到達確認。許可ホスト www.city.nerima.tokyo.jp（city.*/.tokyo.jp）一致。両ページとも練馬区自身の当該制度ページで、国制度・都制度の一般説明や介護タクシーとの混同なし。更新日は福祉タクシー=2026-04-01、燃料費助成=2025-08-01で受付終了の表示なし＝現行。
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.adachi.tokyo.jp/shogai/20220301.html', '敵対的検証を実施。program.officialUrl（https://www.city.adachi.tokyo.jp/shogai/20220301.html）をWebFetchで取得し、以下を確認した。(a)到達=正常に内容取得。(b)許可ホスト=www.city.adachi.tokyo.jp（city.*＋.tokyo.jp）で足立区公式、FAQ専用ドメインではなく適合。(c)当該区ページ=ページタイトル「福祉タクシー・自動車燃料助成券の交付｜足立区」で足立区独自の福祉タクシー券/燃料費助成そのもの。(d)現行=更新日2026-06-08、受付終了の記載なし。(e)国制度・都制度の一般説明や介護保険の介護タクシー（通院等乗降介助）との混同なし＝区独自の障がい者移動支援制度として正しく記載。(f)対象の一部を全体と誤記していない＝対象等級は概括し「公式で確認」を付記。(g)複数制度の無理な統合なし＝タクシー券と燃料費助成は同一の助成券で双方に利用できる選択肢のため1件統合は妥当（公式ページで同一制度と確認）。(h)FORBIDDEN/断定なし＝対象等級・交付額・回数は概括し「' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='adachi' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'not_found_on_official_site', '2026-06-24', 'https://www.city.katsushika.lg.jp/faq/1030271/1007660/1008538/1008578.html', '敵対的検証の結果、一次調査の判定（not_found_on_official_site）を妥当として支持する。\n\n【検証手順と結果】\n1. 証拠URL（https://www.city.katsushika.lg.jp/faq/1030271/1007660/1008538/1008578.html）をWebFetchで再到達確認。許可ホスト city.katsushika.lg.jp（.lg.jp、葛飾区公式）。FAQ専用ドメインではなく区公式サイト内のFAQページ。到達OK。\n2. 内容を再確認：「平成21年4月1日から、これまでの外出支援事業（福祉タクシー券）、重度身体障害者移動支援モデル事業及び自動車燃料費の補助事業は、心身障害者福祉手当（外出支援分）として事業を行っており、福祉タクシー券配布という単体の事業はなくなりました」と明記。すなわち福祉タクシー券・自動車燃料費助成は2009-04-01に廃止され、現金給付の心身障害者福祉手当（外出支援分）へ統合済み。\n3. 補強検証として葛飾区公式の「サービス・助成・減免」一覧（https://www.city.katsus' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='katsushika' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
insert into public.municipality_topic_coverage (municipality_id, support_topic_id, research_status, last_researched_at, official_source_url, research_note) select m.id, t.id, 'found', '2026-06-24', 'https://www.city.edogawa.tokyo.jp/e041/kenko/fukushikaigo/shogaisha/service/seikatsu/gaishutsu/taxi.html', '敵対的検証完了。江戸川区公式サイト（www.city.edogawa.tokyo.jp＝city.*かつ.tokyo.jpの許可ホスト）で福祉タクシー券ページ（e041/.../taxi.html）を直接WebFetchで照合。(a)到達OK (b)許可ホスト一致 (c)江戸川区自身の福祉タクシー券の当該区ページ（国・都の一般説明ではない） (d)更新日2026-05-29・令和8年4月1日現在＝現行、受付終了でない (e)介護タクシー等との混同なし、区独自制度 (f)対象者は概括＋uncertainFields記載で部分を全体と誤認していない (g)複数制度の不当統合なし——公式ページ本文に「燃料費助成との選択制です」と明記されており、福祉タクシー券と自動車燃料費助成は同一移動支援制度の正規の選択肢。統合は妥当。燃料費助成ページ（nenryo.html）も別途WebFetchで照合し、対象（上肢1～2級は本人運転のみ／視覚・愛の手帳は介護者運転のみ／下肢等は本人または介護者）・月額上限3,000円・給油なき月は対象外・選択制を確認。(h)交付額/対象等級/回数はすべて「公式によると」' from public.municipalities m join public.prefectures pr on pr.id=m.prefecture_id, public.support_topics t where pr.slug='tokyo' and m.slug='edogawa' and t.slug='welfare-taxi' on conflict (municipality_id, support_topic_id) do update set research_status=excluded.research_status, last_researched_at=excluded.last_researched_at, official_source_url=excluded.official_source_url, research_note=excluded.research_note;
